'use client';

import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';

export default function CrmHeader() {
  const pathname = usePathname();
  const router = useRouter();
  const isLogin = pathname === '/crm/login';

  async function signOut() {
    await fetch('/api/crm/logout', { method: 'POST' });
    router.push('/crm/login');
    router.refresh();
  }

  return (
    <header className="border-b border-gray-200 bg-white sticky top-0 z-10">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-14 flex items-center justify-between gap-4">
        <div className="flex items-center gap-5 min-w-0">
          <Link
            href="/"
            className="text-sm font-semibold text-primary hover:text-primary-dark shrink-0"
          >
            EcoLawns
          </Link>
          {!isLogin && (
            <nav className="flex items-center gap-1 text-sm" aria-label="CRM">
              <Link
                href="/crm"
                className={`px-2.5 py-1.5 rounded-md transition-colors ${
                  pathname === '/crm'
                    ? 'bg-primary/10 text-primary-dark font-semibold'
                    : 'text-gray-600 hover:text-primary hover:bg-gray-50'
                }`}
              >
                Leads
              </Link>
              <Link
                href="/crm/leads/new"
                className={`px-2.5 py-1.5 rounded-md transition-colors ${
                  pathname === '/crm/leads/new'
                    ? 'bg-primary/10 text-primary-dark font-semibold'
                    : 'text-gray-600 hover:text-primary hover:bg-gray-50'
                }`}
              >
                New lead
              </Link>
            </nav>
          )}
        </div>
        {isLogin ? (
          <span className="text-xs text-gray-400 truncate">Staff sign in</span>
        ) : (
          <button
            type="button"
            onClick={signOut}
            className="shrink-0 px-3 py-1.5 text-sm font-medium text-gray-600 rounded-lg border border-gray-200 hover:bg-gray-50 hover:text-gray-900 transition-colors"
          >
            Sign out
          </button>
        )}
      </div>
    </header>
  );
}
